      "successCondition": "docked_at_base != null",
      "timeoutTicks": 3
    },
    {
      "task": "explore",
      "goal": "Check credit balance after the undock-redock cycle. Compare to the 94 credits we started with. If credits changed, docking has a fee. If unchanged, the credit drain is from travel or selling. Record findings. Then check if there is a way to sell cargo directly (instant sell) vs placing a sell order (which might have listing fees). Look for any 'sell directly' or 'quick sell' option distinct from market orders.",
      "model": "sonnet",
      "successCondition": "credits >= 90",
      "timeoutTicks": 6
    }
  ]
}
